760	/// C: `sort(L)` — implements `table.sort(t [, comp])`.
761	///
762	/// ```c
763	/// static int sort (lua_State *L) {
764	///   lua_Integer n = aux_getn(L, 1, TAB_RW);
765	///   if (n > 1) {
766	///     luaL_argcheck(L, n < INT_MAX, 1, "array too big");
767	///     if (!lua_isnoneornil(L, 2))
768	///       luaL_checktype(L, 2, LUA_TFUNCTION);
769	///     lua_settop(L, 2);
770	///     auxsort(L, 1, (IdxT)n, 0);
771	///   }
772	///   return 0;
773	/// }
774	/// ```
775	pub fn sort(state: &mut LuaState) -> Result<usize, LuaError> {
776	    let n = aux_getn(state, 1, TAB_RW)?;
777	    if n > 1 {
778	        if !(n < i32::MAX as i64) {
779	            return Err(LuaError::arg_error(1, "array too big"));
780	        }
781	        if !matches!(state.type_at(2), LuaType::None | LuaType::Nil) {
782	            state.check_arg_type(2, LuaType::Function)?;
783	        }
784	        // C: lua_settop(L, 2) — discard any extra arguments.
785	        // Must go through the public C-API set_top (relative to the call
786	        // frame); the inherent LuaState::set_top treats its argument as
787	        // an absolute stack slot and would corrupt the frame.
788	        lua_vm::api::set_top(state, 2)?;
789	        aux_sort(state, 1, n as IdxT, 0)?;
790	    }
791	    Ok(0)
792	}
793	
794	// ─── Registration ─────────────────────────────────────────────────────────────
795	
796	/// C: `tab_funcs[]` — the function registration table for `require("table")`.
797	///
798	/// ```c
799	/// static const luaL_Reg tab_funcs[] = {
800	///   {"concat", tconcat}, {"insert", tinsert}, {"pack", tpack},
801	///   {"unpack", tunpack}, {"remove", tremove}, {"move", tmove},
802	///   {"sort", sort}, {NULL, NULL}
803	/// };
804	/// ```
805	///
806	/// PORT NOTE: In Rust we represent this as a slice of `(&[u8], fn-ptr)` pairs;
807	/// the sentinel `{NULL, NULL}` is implicit (the slice has a known length).
808	pub const TABLE_FUNCS: &[(&[u8], fn(&mut LuaState) -> Result<usize, LuaError>)] = &[
809	    (b"concat", concat),
810	    (b"insert", insert),
811	    (b"pack", pack),
812	    (b"unpack", unpack),
813	    (b"remove", remove),
814	    (b"move", tmove),
815	    (b"sort", sort),
816	];
817	
818	// ─── Module opener ────────────────────────────────────────────────────────────
819	
820	/// C: `luaopen_table(L)` — open the `table` library.
821	///
822	/// ```c
823	/// LUAMOD_API int luaopen_table (lua_State *L) {
824	///   luaL_newlib(L, tab_funcs);
825	///   return 1;
